{
  "mode": "io",
  "tests": [
    {
      "name": "valid_message",
      "input": "{\"message\": \"Hello, World!\"}",
      "output": "{\"status\": \"success\", \"message\": \"Message received.\"}",
      "notes": "Tests a standard valid message input."
    },
    {
      "name": "empty_message",
      "input": "{\"message\": \"\"}",
      "output": "{\"status\": \"error\", \"message\": \"Message cannot be empty.\"}",
      "notes": "Tests handling of an empty message input."
    },
    {
      "name": "long_message",
      "input": "{\"message\": \"" + "a".repeat(1001) + "\"}",
      "output": "{\"status\": \"error\", \"message\": \"Message exceeds maximum length.\"}",
      "notes": "Tests the system's response to a message that exceeds the length limit."
    },
    {
      "name": "special_characters",
      "input": "{\"message\": \"!@#$%^&*()\"}",
      "output": "{\"status\": \"success\", \"message\": \"Message received.\"}",
      "notes": "Tests handling of special characters in the message."
    },
    {
      "name": "missing_message_key",
      "input": "{}",
      "output": "{\"status\": \"error\", \"message\": \"Missing message key.\"}",
      "notes": "Tests the response when the message key is missing."
    },
    {
      "name": "null_message",
      "input": "{\"message\": null}",
      "output": "{\"status\": \"error\", \"message\": \"Message cannot be null.\"}",
      "notes": "Tests handling of a null value for the message."
    },
    {
      "name": "whitespace_message",
      "input": "{\"message\": \"   \"}",
      "output": "{\"status\": \"error\", \"message\": \"Message cannot be empty.\"}",
      "notes": "Tests handling of a message that consists only of whitespace."
    },
    {
      "name": "valid_message_with_metadata",
      "input": "{\"message\": \"Hello!\", \"metadata\": {\"user\": \"test_user\", \"timestamp\": \"2023-10-01T12:00:00Z\"}}",
      "output": "{\"status\": \"success\", \"message\": \"Message received with metadata.\"}",
      "notes": "Tests the system's ability to handle messages with additional metadata."
    }
  ],
  "assumptions": "Messages must be non-empty strings and adhere to specified constraints.",
  "notes": "Ensure to validate both the content and structure of the input."
}
